// GEE Code Example for MOD13Q1 - NDVI Time Series
var modisNDVI = ee.ImageCollection('MODIS/061/MOD13Q1');

// Define region of interest
var roi = ee.Geometry.Rectangle([100, 30, 110, 40]); // Example: China region

// Filter by date and region
var filtered = modisNDVI
  .filterDate('2020-01-01', '2020-12-31')
  .filterBounds(roi)
  .select('NDVI');

// Apply scale factor
var ndviScaled = filtered.map(function(img) {
  return img.multiply(0.0001)
    .set('system:time_start', img.get('system:time_start'));
});

// Create chart
var chart = ui.Chart.image.series({
  imageCollection: ndviScaled,
  region: roi,
  reducer: ee.Reducer.mean(),
  scale: 250,
  xProperty: 'system:time_start'
}).setOptions({
  title: 'MOD13Q1 NDVI Time Series',
  vAxis: {title: 'NDVI'},
  hAxis: {title: 'Date'}
});
print(chart);

// Visualize on map
var ndviVis = {min: 0, max: 1, palette: ['red', 'yellow', 'green']};
Map.addLayer(ndviScaled.mean(), ndviVis, 'Mean NDVI 2020');
Map.centerObject(roi, 6);

