// GEE Code for MOD09GA - Custom VI computation
var mod09 = ee.ImageCollection('MODIS/061/MOD09GA');

var roi = ee.Geometry.Rectangle([100, 30, 110, 40]);

// Function to compute NDVI from surface reflectance
var addNDVI = function(image) {
  var ndvi = image.normalizedDifference(['sur_refl_b02', 'sur_refl_b01'])
    .rename('NDVI');
  return image.addBands(ndvi);
};

// Get collection with NDVI band
var withNDVI = mod09
  .filterDate('2020-06-01', '2020-06-30')
  .filterBounds(roi)
  .map(addNDVI);

// Chart NDVI time series
var chart = ui.Chart.image.series({
  imageCollection: withNDVI.select('NDVI'),
  region: roi,
  reducer: ee.Reducer.mean(),
  scale: 500,
  xProperty: 'system:time_start'
}).setOptions({title: 'Custom NDVI from MOD09GA'});
print(chart);

var ndviVis = {min: 0, max: 1, palette: ['red', 'yellow', 'green']};
Map.addLayer(withNDVI.select('NDVI').mean(), ndviVis, 'Mean Custom NDVI');
Map.centerObject(roi, 6);

